export const StorageService = {
  async saveDriveConfig(link: string) {
    localStorage.setItem('phant_drive_folder_link', link);
    window.dispatchEvent(new Event('storage'));
    return { success: true };
  },
  async getSavedDriveConfig() {
    return localStorage.getItem('phant_drive_folder_link') || `https://drive.google.com/drive/folders/${DEFAULT_DRIVE_FOLDER_ID}`;
  },
  async fetchDriveFiles(inputLink: string) {
    const folderId = this.extractFolderId(inputLink);
    let files: any[] = [];
    let success = false;

    // 1. Tentar via API Oficial (Recomendado)
    try {
      const token = await GoogleApiService.getAccessToken();
      if (token) {
        const query = encodeURIComponent(`'${folderId}' in parents and trashed = false`);
        // Includes iconLink and sorts by folders first
        const fields = encodeURIComponent("files(id, name, mimeType, size, modifiedTime, thumbnailLink, webViewLink, iconLink)");
        const url = `https://www.googleapis.com/drive/v3/files?q=${query}&fields=${fields}&pageSize=200&orderBy=folder,name`;

        const res = await fetch(url, {
          headers: { Authorization: `Bearer ${token}` }
        });

        if (res.ok) {
          const data = await res.json();
          files = data.files || [];
          success = true;
        } else {
          console.warn(`Drive API Error ${res.status}:`, res.statusText);
        }
      }
    } catch (e) {
      console.warn("Google API Direct Fetch failed, trying fallback...", e);
    }

    // 2. Fallback para Proxy Script (Apenas se API falhar)
    if (!success) {
      const finalUrl = `${PROXY_URL}?id=${folderId}&_t=${Date.now()}`;
      try {
        const response = await fetch(finalUrl, { method: 'GET', mode: 'cors' });
        if (!response.ok) throw new Error(`HTTP_ERROR_${response.status}`);
        const data = await response.json();
        files = data.files || data.items || [];
        success = true;
      } catch (err: any) { 
        console.warn("Proxy Drive indisponível ou bloqueado.", err.message);
      }
    }

    if (!success) {
       throw new Error("Não foi possível carregar os arquivos. Verifique a conexão ou faça login novamente.");
    }

    return this.processFiles(files, folderId);
  },
  processFiles(files: any[], folderId: string) {
    return files.map((file: any) => {
      const fileId = file.id || file.fileId;
      const modTime = file.modifiedTime || null;
      // Prefer API provided thumbnail if available
      const thumb = file.thumbnailLink || `https://drive.google.com/thumbnail?id=${fileId}&sz=w400`;

      return { 
        id: fileId, 
        name: file.name || file.title || "Arquivo sem nome", 
        type: this.mapMimeToType(file.mimeType || ""), 
        size: file.size ? this.formatBytes(parseInt(file.size)) : '---', 
        updatedAt: modTime ? new Date(modTime).toLocaleDateString('pt-BR') : '---', 
        rawUpdatedAt: modTime, 
        url: file.webViewLink || `https://drive.google.com/file/d/${fileId}/view`, 
        previewUrl: `https://drive.google.com/file/d/${fileId}/preview`, 
        downloadUrl: `https://drive.google.com/uc?export=download&id=${fileId}`, 
        thumbnail: thumb, 
        folderId: folderId, 
        raw: file 
      };
    });
  },
  extractFolderId(url: string) {
    const match = url.match(/(?:folders\/|id=)([-\w]{25,})/);
    return match ? match[1] : DEFAULT_DRIVE_FOLDER_ID;
  },
  mapMimeToType(mimeType: string) {
    const mime = (mimeType || '').toLowerCase();
    if (mime === 'application/pdf') return 'pdf';
    if (mime === 'application/vnd.google-apps.document') return 'gdoc';
    if (mime === 'application/vnd.google-apps.spreadsheet') return 'gsheet';
    if (mime === 'application/vnd.google-apps.presentation') return 'gslides';
    if (mime.includes('video/')) return 'video';
    if (mime.includes('image/')) return 'image';
    return 'unknown';
  },
  formatBytes(bytes: number) {
    if (!bytes || isNaN(bytes)) return '---';
    const i = Math.floor(Math.log(bytes) / Math.log(1024));
    const sizes = ['B', 'KB', 'MB', 'GB'];
    return (bytes / Math.pow(1024, i)).toFixed(1) + ' ' + sizes[i];
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { AppCustomization, ProposalItem, ProposalMetadata, ProposalRecord, StrategicMapItem, SolutionItem } from '../types';
import { SupabaseService } from '../services/api';
import ProposalPresentation from './ProposalPresentation';
import { generateStrategicMapping } from '../services/gemini';

// Background pattern for PDF
const PATTERN_BG = "data:image/svg+xml,%3Csvg width='20' height='20' viewBox='0 0 20 20' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='%239C92AC' fill-opacity='0.2' fill-rule='evenodd'%3E%3Ccircle cx='3' cy='3' r='1'/%3E%3Ccircle cx='13' cy='13' r='1'/%3E%3C/g%3E%3C/svg%3E";

interface ProposalBuilderProps {
  appConfig: AppCustomization;
}

type ViewMode = 'EDITOR' | 'PREVIEW';

export default function ProposalBuilder({ appConfig }: ProposalBuilderProps) {
  const [mode, setMode] = useState<ViewMode>('EDITOR');
  const [showPresentation, setShowPresentation] = useState(false);
  const [items, setItems] = useState<ProposalItem[]>([]);
  const [allSolutions, setAllSolutions] = useState<SolutionItem[]>([]);
  const [history, setHistory] = useState<ProposalRecord[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showItemSelector, setShowItemSelector] = useState(false);

  // Metadados da Proposta
  const [metadata, setMetadata] = useState<ProposalMetadata>({
    clientName: '',
    industry: '',
    headline: 'Plano de Aceleração',
    consultant: '',
    date: new Date().toLocaleDateString('pt-BR'),
    discountType: 'percent',
    discountValue: 0,
    observations: '',
    // Campos para IA
    meetingNotesPains: '',
    meetingNotesDesires: ''
  });

  // Mapeamento Estratégico (Cenário De/Para)
  const [comparisons, setComparisons] = useState<StrategicMapItem[]>([
      { current: 'Dependência de Indicação', desired: 'Máquina de Vendas Previsível' },
      { current: 'Baixa Conversão', desired: 'Processo Comercial Validado' }
  ]);

  // Carregar dados iniciais
  useEffect(() => {
    const loadInitialData = async () => {
        // 1. Carregar Itens do LocalStorage
        const savedItems = localStorage.getItem('phant_current_proposal');
        if (savedItems) setItems(JSON.parse(savedItems));

        // 2. Carregar Soluções para o Seletor
        const solutions = await SupabaseService.fetchSolutions();
        setAllSolutions(solutions);

        // 3. Carregar Usuário Logado
        try {
             const { data: { user } } = await import('../services/api').then(m => m.supabase.auth.getUser());
             if (user?.user_metadata?.full_name) {
                 setMetadata(prev => ({ ...prev, consultant: user.user_metadata.full_name }));
             }
        } catch {}

        // 4. Carregar Histórico
        fetchHistory();
    };
    loadInitialData();
  }, []);

  const fetchHistory = async () => {
      const recs = await SupabaseService.fetchProposalsHistory();
      setHistory(recs);
  };

  const calculateTotals = () => {
      const subtotal = items.reduce((acc, curr) => acc + curr.totalPrice, 0);
      let finalPrice = subtotal;
      let discountAmount = 0;

      if (metadata.discountValue && metadata.discountValue > 0) {
          if (metadata.discountType === 'percent') {
              discountAmount = subtotal * (metadata.discountValue / 100);
          } else {
              discountAmount = metadata.discountValue;
          }
          finalPrice = Math.max(0, subtotal - discountAmount);
      }

      return { subtotal, discountAmount, finalPrice };
  };

  const { subtotal, discountAmount, finalPrice } = calculateTotals();

  // --- ACTIONS ---

  const handleSaveProposal = async () => {
      if (!metadata.clientName) {
          alert("Por favor, preencha o nome do cliente.");
          return;
      }
      setIsSaving(true);

      // Salva o Mapa Estratégico dentro do metadata para persistência
      const metadataToSave = {
        ...metadata,
        strategicMap: comparisons
      };

      const res = await SupabaseService.saveProposal(
          metadata.clientName, 
          metadata.industry, 
          finalPrice, 
          metadata.consultant, 
          items, 
          metadataToSave
      );

      if (res.success) {
          alert("Proposta salva no histórico!");
          fetchHistory();
      } else {
          alert("Erro ao salvar: " + res.message);
      }
      setIsSaving(false);
  };

  const handleLoadHistory = (record: ProposalRecord) => {
      if (confirm(`Deseja carregar a proposta de ${record.client_name}? As alterações atuais não salvas serão perdidas.`)) {
          setMetadata(record.metadata);
          setItems(record.items);

          // Carrega Mapa Estratégico se existir no metadata, senão mantém o atual ou padrão
          if ((record.metadata as any).strategicMap) {
              setComparisons((record.metadata as any).strategicMap);
          }

          localStorage.setItem('phant_current_proposal', JSON.stringify(record.items));
          window.scrollTo({ top: 0, behavior: 'smooth' });
      }
  };

  const handleDeleteHistory = async (id: string) => {
      if (confirm("Tem certeza que deseja excluir esta proposta do histórico?")) {
          const res = await SupabaseService.deleteProposal(id);
          if (res.success) {
              fetchHistory();
          } else {
              alert("Erro ao excluir: " + res.message);
          }
      }
  };

  const handleAnalyzeContext = async () => {
      if (!metadata.clientName) {
          alert("Preencha o nome do cliente antes de analisar.");
          return;
      }
      setIsAnalyzing(true);
      try {
          const result = await generateStrategicMapping(metadata);
          if (result && result.length > 0) {
              setComparisons(result);
          } else {
              alert("A IA não conseguiu gerar o mapa. Tente adicionar mais detalhes nas observações/dores.");
          }
      } catch (e) {
          alert("Erro na análise IA.");
      } finally {
          setIsAnalyzing(false);
      }
  };

  const removeItem = (instanceId: string) => {
      const newItems = items.filter(i => i.instanceId !== instanceId);
      setItems(newItems);
      localStorage.setItem('phant_current_proposal', JSON.stringify(newItems));
  };

  const addItem = (sol: SolutionItem) => {
      const newItem: ProposalItem = {
          instanceId: `${sol.id}-${Date.now()}`,
          solutionId: sol.id,
          name: sol.solucao,
          basePrice: sol.valor_base_num || 0,
          selectedOptions: [],
          totalPrice: sol.valor_base_num || 0,
          duration: sol.duracao,
          description: sol.descricao,
          deliverables: sol.entregaveis,
          promessa: sol.promessa,
          publico_alvo: sol.publico_alvo,
          resultado_esperado: sol.resultado_esperado,
          diferenciais: sol.diferenciais
      };
      const nextItems = [...items, newItem];
      setItems(nextItems);
      localStorage.setItem('phant_current_proposal', JSON.stringify(nextItems));
      setShowItemSelector(false);
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  // --- RENDER: APRESENTAÇÃO (SLIDES) ---
  if (showPresentation) {
      return (
          <ProposalPresentation 
             metadata={metadata}
             items={items}
             strategicMap={comparisons}
             appConfig={appConfig}
             onClose={() => setShowPresentation(false)}
          />
      );
  }

  // --- RENDER: LAYOUT DE IMPRESSÃO (PREVIEW - PDF) ---
