          background: ${PHANT_PURPLE};
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        }
        .btn-presentation:hover {
          transform: scale(1.05);
          box-shadow: 0 0 30px rgba(97, 19, 204, 0.4);
